from flask import Flask, request, jsonify
import logging
import datetime
import os

app = Flask(__name__)

# Set up logging configuration
logging.basicConfig(filename='application.log', level=logging.INFO,
                    format='%(asctime)s [%(levelname)s] %(message)s')

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')
    email = data.get('email')
    ip_address = request.remote_addr
    user_agent = request.user_agent.string

    # Validate input data (simplified for demonstration purposes)
    if not all([username, password, email]):
        logging.warning(f'Invalid login attempt: {username}, {ip_address}')
        return jsonify({'message': 'Invalid credentials'}), 401

    # Store login attempt in the log
    logging.info(
        f'User logged in successfully: {username}, {email}, {ip_address}, {user_agent}'
    )

    return jsonify({'message': 'Login successful'}), 200


if __name__ == '__main__':
    app.run(debug=True)